    14→export const paymentService = {
    15→  async createPayment(
    16→    request: CreatePaymentRequest,
    17→  ): Promise<CreatePaymentResponse> {
    18→    const api = await getApi();
    19→
    20→    // For FEE payments, use amountTotal instead of walletAmount
    21→    const payload =
    22→      request.purpose === "FEE"
    23→        ? {
    24→            purpose: request.purpose,
    25→            amountTotal: request.amountTotal,
    26→            taxAmount: request.taxAmount,
    27→            method: request.method,
    28→            currency: request.currency,
    29→            idempotencyKey: request.idempotencyKey,
    30→          }
    31→        : {
    32→            purpose: request.purpose,
    33→            walletAmount: request.walletAmount,
    34→            method: request.method,
    35→            currency: request.currency,
    36→            idempotencyKey: request.idempotencyKey,
    37→          };
    38→
    39→    const { data } = await api.post<CreatePaymentResponse>(
    40→      API_ROUTES.PAYMENTS.CREATE,
    41→      payload,
    42→      {
    43→        headers: request.idempotencyKey
    44→          ? { "Idempotency-Key": request.idempotencyKey }
    45→          : undefined,
    46→      },
    47→    );
    48→
    49→    return data;
    50→  },
    51→
    52→  async getPayment(id: string): Promise<Payment> {
    53→    const api = await getApi();
    54→
    55→    const { data } = await api.get<Payment>(API_ROUTES.PAYMENTS.GET(id));
    56→
    57→    return data;
    58→  },
    59→
    60→  async listPayments(params?: {
    61→    limit?: number;
    62→    skip?: number;
    63→  }): Promise<PaymentListResponse> {
    64→    const api = await getApi();
    65→
    66→    const { data } = await api.get<PaymentListResponse>(
    67→      API_ROUTES.PAYMENTS.LIST,
    68→      { params },
    69→    );
    70→
    71→    return data;
    72→  },
    73→
    74→  async createCheckoutSession(
    75→    request: CreateCheckoutSessionRequest,
    76→  ): Promise<CreateCheckoutSessionResponse> {
    77→    const api = await getApi();
    78→
    79→    const { data } = await api.post<CreateCheckoutSessionResponse>(
    80→      API_ROUTES.STRIPE_CHECKOUT,
    81→      request,
    82→    );
    83→
    84→    return data;
    85→  },
    86→
    87→  async createPaymentIntent(
    88→    request: CreatePaymentIntentRequest,
    89→  ): Promise<CreatePaymentIntentResponse> {
