    15→export interface CreateFeePaymentRequest {
    16→  amountTotal: number; // in cents
    17→  taxAmount?: number; // in cents
    18→  method: PaymentMethod;
    19→  currency?: string;
    20→  idempotencyKey?: string;
    21→}
    22→
    23→export interface PayFeeWithPayPalRequest {
