    29→
    30→/**
    31→ * Hook for creating FEE payment
    32→ */
    33→export function useCreateFeePayment() {
    34→  const queryClient = useQueryClient();
    35→
    36→  return useMutation({
    37→    mutationFn: (request: CreateFeePaymentRequest) =>
    38→      paymentService.createPayment({
    39→        purpose: PaymentPurpose.FEE,
    40→        amountTotal: request.amountTotal,
    41→        taxAmount: request.taxAmount,
    42→        method: request.method,
    43→        currency: request.currency,
    44→        idempotencyKey: request.idempotencyKey,
    45→      }),
    46→    onSuccess: () => {
    47→      queryClient.invalidateQueries({
    48→        queryKey: ApiKeys.payments(),
    49→      });
    50→      queryClient.invalidateQueries({
    51→        queryKey: ApiKeys.wallet(),
    52→      });
    53→    },
    54→    onError: (error: unknown) => {
    55→      toast.error(getErrorMessage(error, "Failed to create fee payment"));
    56→    },
    57→  });
    58→}
    59→
    60→/**
    61→ * Hook for paying fees via PayPal
    62→ * Creates FEE payment and then PayPal checkout session
    63→ */
    64→export function usePayFeeWithPayPal() {
    65→  const queryClient = useQueryClient();
    66→
    67→  return useMutation({
    68→    mutationFn: async (request: PayFeeWithPayPalRequest) => {
    69→      // Get PayPal method to determine type
    70→      const paypalMethod = await paypalMethodsService.getMethod(
    71→        request.paymentMethodId
    72→      );
    73→
    74→      // Determine PaymentMethod based on PayPal method type
    75→      const paymentMethod: PaymentMethod =
    76→        paypalMethod.type === "PAYPAL_ACCOUNT"
    77→          ? PaymentMethodEnum.PAYPAL_ACCOUNT
    78→          : PaymentMethodEnum.PAYPAL_BANK;
    79→
    80→      // Create FEE payment
    81→      const payment = await paymentService.createPayment({
    82→        purpose: PaymentPurpose.FEE,
    83→        amountTotal: request.amountTotal,
    84→        taxAmount: request.taxAmount,
    85→        method: paymentMethod,
    86→        currency: request.currency,
    87→      });
    88→
    89→      // Create PayPal checkout session
    90→      const checkoutSession =
    91→        await paypalCheckoutService.createCheckoutSession({
    92→          paymentId: payment.id,
    93→          paymentMethodId: request.paymentMethodId,
    94→        });
    95→
    96→      return {
    97→        payment,
    98→        checkoutSession,
    99→      };
   100→    },
   101→    onSuccess: (data) => {
   102→      queryClient.invalidateQueries({
   103→        queryKey: ApiKeys.payments(),
   104→      });
   105→      queryClient.invalidateQueries({
   106→        queryKey: ApiKeys.wallet(),
   107→      });
   108→
   109→      // Redirect to PayPal
   110→      if (data.checkoutSession.url) {
   111→        window.location.href = data.checkoutSession.url;
   112→      }
   113→    },
   114→    onError: (error: unknown) => {
   115→      toast.error(
   116→        getErrorMessage(error, "Failed to process PayPal fee payment")
   117→      );
   118→    },
   119→  });
   120→}
